# Step 2: Filter by hardware constraints
def filter_by_hardware(models, max_ram_gb=16):
    viable = []
    for m in models:
        ram = estimate_ram_gb(m["params_b"], m.get("quant_bits", 16))
        if ram <= max_ram_gb:
            viable.append({**m, "ram_gb": ram})
    return viable

# Laptop scenario: 16 GB RAM available
laptop_models = filter_by_hardware(models, max_ram_gb=16)

print(f"{len(laptop_models)} models fit in 16GB RAM:")
for m in laptop_models:
    print(f"  {m['name']:<30} RAM≈{m['ram_gb']:.1f}GB  avg={m['avg']}")

# Step 3: Rank by weighted composite score
def rank_models(models, task_weights=None):
    if task_weights is None:
        task_weights = {"avg": 1.0}
    for m in models:
        score = sum(m.get(k, m["avg"]) * w for k, w in task_weights.items())
        m["weighted"] = round(score, 2)
    return sorted(models, key=lambda x: x["weighted"], reverse=True)

# General assistant: just use the average
ranked = rank_models(laptop_models)
for m in ranked:
    print(f"  {m['name']:<30} weighted={m['weighted']:<8} RAM≈{m['ram_gb']:.1f}GB")

# Full selection pipeline as a reusable function
def select_model(models, min_avg=40, max_ram_gb=16,
                 task_weights=None):
    """Select the best model from Open LLM Leaderboard data."""
    if task_weights is None:
        task_weights = {"avg": 1.0}
    viable = []
    for m in models:
        ram = estimate_ram_gb(m["params_b"], m.get("quant_bits", 16))
        if ram > max_ram_gb or m["avg"] < min_avg:
            continue
        score = sum(m.get(k, m["avg"]) * w for k, w in task_weights.items())
        viable.append({**m, "ram_gb": ram, "weighted": round(score, 2)})
    return sorted(viable, key=lambda x: x["weighted"], reverse=True)

# Scenario A: General Homie assistant on a laptop
homie_picks = select_model(models, min_avg=40, max_ram_gb=8)
print("Homie assistant (8GB RAM):")
for m in homie_picks:
    print(f"  {m['name']} → score={m['weighted']} RAM≈{m['ram_gb']}GB")

# Scenario B: Math tutor — weight MATH and BBH benchmarks
math_picks = select_model(models, min_avg=30, max_ram_gb=16,
                          task_weights={"math": 0.5, "bbh": 0.3, "avg": 0.2})
print("\nMath tutor (16GB RAM):")
for m in math_picks:
    print(f"  {m['name']} → score={m['weighted']} RAM≈{m['ram_gb']}GB")

# Quantization impact check
def quant_comparison(params_b):
    print(f"\n{params_b}B model quantization options:")
    for bits in [16, 8, 4]:
        ram = estimate_ram_gb(params_b, bits)
        quality = {16: "100%", 8: "~99%", 4: "~95%"}[bits]
        print(f"  Q{bits}: {ram:.1f} GB — {quality} quality")

quant_comparison(8)
